import { useMutation } from "@tanstack/react-query";
import { createFileRoute } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { useState, type FormEvent } from "react";
import { z } from "zod";
import { eq } from "drizzle-orm";

import { DashboardLayout } from "#/components/layout/dashboard";
import { MustAuthenticate, redirectIfSignedOut } from "#/lib/auth";
import { DatabaseProvider } from "#/lib/provider";
import { t } from "#/lib/server/database";

export const Route = createFileRoute("/vendor/new")({
  component: VendorInsertPage,
  beforeLoad: async ({ context }) => {
    await redirectIfSignedOut(context);
  },
});

type VendorInsertResult = {
  vendor_id: number;
  vendor_name: string;
  vendor_address: string | null;
};

const VendorInsertSchema = z.object({
  vendor_name: z.string().trim().min(1, "Vendor name is required"),
  house_number: z.string().trim().min(1, "House number is required"),
  street: z.string().trim().min(1, "Street is required"),
  city: z.string().trim().min(1, "City is required"),
  state: z.string().trim().min(1, "State is required"),
  postal_code: z.string().trim().min(1, "Postal code is required"),
});

const insertVendor = createServerFn()
  .middleware([DatabaseProvider, MustAuthenticate])
  .inputValidator(VendorInsertSchema)
  .handler(async ({ data, context }) => {
    const vendor_address = `${data.house_number} ${data.street}, ${data.city}, ${data.state} ${data.postal_code}`;

    const existing = await context.db
      .select()
      .from(t.vendor)
      .where(eq(t.vendor.vendor_name, data.vendor_name))
      .limit(1);

    if (existing.length) {
      const v = existing[0];
      return {
        vendor_id: v.vendor_id,
        vendor_name: v.vendor_name,
        vendor_address: v.vendor_address
      };
    }

    const inserted = await context.db
      .insert(t.vendor)
      .values({
        vendor_name: data.vendor_name,
        vendor_address,
      })
      .returning()
      .then((rows) => rows[0]);

    if (!inserted) {
      throw new Error("Failed to create vendor");
    }

    return {
      vendor_id: inserted.vendor_id,
      vendor_name: inserted.vendor_name,
      vendor_address: inserted.vendor_address,
    };
  });

function VendorInsertPage() {
  const mutation = useMutation({ mutationFn: insertVendor });
  const [loading, setLoading] = useState(false);
  const [vendorName, setVendorName] = useState("");
  const [houseNumber, setHouseNumber] = useState("");
  const [street, setStreet] = useState("");
  const [city, setCity] = useState("");
  const [stateRegion, setStateRegion] = useState("");
  const [postalCode, setPostalCode] = useState("");
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);
  const [lastInserted, setLastInserted] = useState<VendorInsertResult | null>(null);

  const handleInsert = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setLoading(true);
    setMessage(null);
    setLastInserted(null);

    try {
      const payload = {
        vendor_name: vendorName.trim(),
        house_number: houseNumber.trim(),
        street: street.trim(),
        city: city.trim(),
        state: stateRegion.trim(),
        postal_code: postalCode.trim(),
      };

      const result = await mutation.mutateAsync({
        data: payload,
      });

      setLastInserted(result);
      setVendorName("");
      setHouseNumber("");
      setStreet("");
      setCity("");
      setStateRegion("");
      setPostalCode("");
      setMessage({
        type: "success",
        text: `Vendor created successfully (ID: ${result.vendor_id}).`,
      });
    } catch (err) {
      const text =
        err instanceof Error ? err.message : "Unexpected error while inserting vendor. Try again.";
      setMessage({ type: "error", text });
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <DashboardLayout title="Vendors">
      <div className="mx-auto max-w-3xl rounded-2xl border border-white/10 bg-white/5 p-6 shadow-[0_18px_70px_rgba(15,23,42,0.55)] backdrop-blur">
        <h1 className="mb-2 text-2xl font-semibold">New Vendor</h1>
        <p className="mb-6 text-sm text-slate-300">
          Insert a new row into the <code>vendor</code> table. <code>vendor_id</code> is
          auto-generated by Supabase.
        </p>

        <form onSubmit={handleInsert} className="space-y-4">
          <label className="flex flex-col gap-2 text-sm">
            <span className="text-slate-300">Vendor Name</span>
            <input
              value={vendorName}
              onChange={(e) => setVendorName(e.target.value)}
              placeholder="Acme Corp"
              className="w-full rounded-lg border border-white/10 bg-white/5 px-3 py-3 text-sm text-slate-100 outline-none placeholder:text-slate-400"
            />
          </label>

          <div className="grid gap-3 md:grid-cols-2">
            <label className="flex flex-col gap-2 text-sm">
              <span className="text-slate-300">House Number</span>
              <input
                value={houseNumber}
                onChange={(e) => setHouseNumber(e.target.value)}
                placeholder="123"
                className="w-full rounded-lg border border-white/10 bg-white/5 px-3 py-3 text-sm text-slate-100 outline-none placeholder:text-slate-400"
              />
            </label>

            <label className="flex flex-col gap-2 text-sm">
              <span className="text-slate-300">Street</span>
              <input
                value={street}
                onChange={(e) => setStreet(e.target.value)}
                placeholder="Main Street"
                className="w-full rounded-lg border border-white/10 bg-white/5 px-3 py-3 text-sm text-slate-100 outline-none placeholder:text-slate-400"
              />
            </label>

            <label className="flex flex-col gap-2 text-sm">
              <span className="text-slate-300">City</span>
              <input
                value={city}
                onChange={(e) => setCity(e.target.value)}
                placeholder="Springfield"
                className="w-full rounded-lg border border-white/10 bg-white/5 px-3 py-3 text-sm text-slate-100 outline-none placeholder:text-slate-400"
              />
            </label>

            <label className="flex flex-col gap-2 text-sm">
              <span className="text-slate-300">State / Province</span>
              <input
                value={stateRegion}
                onChange={(e) => setStateRegion(e.target.value)}
                placeholder="IL"
                className="w-full rounded-lg border border-white/10 bg-white/5 px-3 py-3 text-sm text-slate-100 outline-none placeholder:text-slate-400"
              />
            </label>

            <label className="flex flex-col gap-2 text-sm md:col-span-2">
              <span className="text-slate-300">Postal Code</span>
              <input
                value={postalCode}
                onChange={(e) => setPostalCode(e.target.value)}
                placeholder="62701"
                className="w-full rounded-lg border border-white/10 bg-white/5 px-3 py-3 text-sm text-slate-100 outline-none placeholder:text-slate-400"
              />
            </label>
          </div>

          <div className="flex justify-end">
            <button
              type="submit"
              disabled={loading}
              className="inline-flex items-center justify-center rounded-lg bg-gradient-to-r from-cyan-400 to-blue-500 px-5 py-3 text-sm font-semibold text-slate-900 shadow-lg shadow-cyan-500/30 transition hover:opacity-95 disabled:cursor-not-allowed disabled:opacity-60"
            >
              {loading ? "Saving…" : "Create Vendor"}
            </button>
          </div>
        </form>

        {message && (
          <div
            className={`mt-4 rounded-lg px-3 py-2 text-sm ${
              message.type === "success"
                ? "border border-emerald-400/40 bg-emerald-400/10 text-emerald-100"
                : "border border-red-400/40 bg-red-400/10 text-red-100"
            }`}
          >
            {message.text}
          </div>
        )}

        {lastInserted && (
          <div className="mt-4 rounded-lg border border-cyan-300/30 bg-cyan-300/10 p-3 text-sm text-cyan-100">
            <p className="font-semibold">Inserted row</p>
            <p>ID: {lastInserted.vendor_id}</p>
            <p>Name: {lastInserted.vendor_name}</p>
            <p>Address: {lastInserted.vendor_address}</p>
          </div>
        )}
      </div>
    </DashboardLayout>
  );
}
